import { defineConfig } from 'astro/config';

// The production domain is set by the owner at deploy time (see docs/DEPLOYMENT_GUIDE.md).
// A placeholder keeps absolute URLs valid; the owner replaces it with their real domain
// (or the *.pages.dev / *.github.io URL) via the SITE_URL env var before/at deploy.
const SITE_URL = process.env.SITE_URL || 'https://data-moat-engine.example.org';

// sitemap.xml is generated by src/pages/sitemap.xml.js (self-contained, no integration dependency).
export default defineConfig({
  site: SITE_URL,
  trailingSlash: 'ignore',
  build: {
    format: 'directory', // clean URLs: /rates/<slug>/ -> index.html
  },
});
